///
/// C: `LUALIB_API int luaL_loadstring(lua_State *L, const char *s)`
pub fn load_string(state: &mut LuaState, s: &[u8]) -> Result<i32, LuaError> {
    // C: return luaL_loadbuffer(L, s, strlen(s), s);
    load_buffer(state, s, s)
