pub fn upvalue_id(state: &LuaState, fidx: i32, n: i32) -> Option<usize> {
    let fi = index_to_value(state, fidx);
    match &fi {
        // C: case LUA_VLCL: return *getupvalref(L, fidx, n, NULL);
