        // C: case LUA_VCCL: if (1 <= n && n <= f->nupvalues) return &f->upvalue[n-1];
        LuaValue::Function(LuaClosure::C(ccl)) => {
            if n >= 1 && n <= ccl.upvalues.len() as i32 {
